    if topic_specs:
        data = json.loads(topic_specs)
        if not isinstance(data, list):
            raise ValueError("--topic-specs must be a JSON list")
        for entry in data:
            if not isinstance(entry, dict) or "name" not in entry:
                raise ValueError("--topic-specs entries must be objects with at least 'name'")
