def cmd_increase_partitions(args, admin: KafkaAdminClient) -> int:
    if not args.topic:
        raise ValueError("--topic is required")
    if args.total_partitions is None:
        raise ValueError("--total-partitions is required")
    np = NewPartitions(total_count=int(args.total_partitions))
    try:
        admin.create_partitions({args.topic: np}, validate_only=args.validate_only)
    except UnknownTopicOrPartitionError:
        raise
    return 0


